def interval_gaps(intervals, start, end):
    if not intervals:
        return [[start, end]] if start < end else []

    # Merge overlapping intervals within the [start, end) range
    merged = []
    for s, e in sorted(intervals):
        if s >= end or e <= start:
            continue
        s = max(s, start)
        e = min(e, end)
        if not merged or merged[-1][1] < s:
            merged.append([s, e])
        else:
            merged[-1][1] = max(merged[-1][1], e)

    gaps = []
    current = start
    for s, e in merged:
        if s > current:
            gaps.append([current, s])
        current = max(current, e)
    if current < end:
        gaps.append([current, end])
    return gaps
